--
-- Table structure for table `im_messages`
--

DROP TABLE IF EXISTS `im_messages`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `im_messages` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `conversation_id` bigint(20) unsigned NOT NULL DEFAULT '0' COMMENT 'ID cuộc hội thoại',
  `from_uid` int(10) unsigned NOT NULL COMMENT 'ID người gửi',
  `to_uid` int(10) unsigned NOT NULL DEFAULT '0' COMMENT 'ID người nhận (chat riêng)',
  `to_group` int(10) unsigned NOT NULL DEFAULT '0' COMMENT 'ID nhóm (chat nhóm)',
  `msg_type` tinyint(4) NOT NULL DEFAULT '1' COMMENT '1-văn bản, 2-hình ảnh, 3-tệp tin, 4-tin hệ thống',
  `content` text NOT NULL COMMENT 'Nội dung tin nhắn',
  `extra` json DEFAULT NULL COMMENT 'Dữ liệu bổ sung',
  `is_read` tinyint(4) NOT NULL DEFAULT '0' COMMENT '0-chưa đọc, 1-đã đọc',
  `is_recall` tinyint(1) NOT NULL DEFAULT '0' COMMENT '0-bình thường, 1-đã thu hồi',
  `read_at` int(10) unsigned DEFAULT NULL COMMENT 'Thời gian đọc',
  `created_at` int(10) unsigned NOT NULL COMMENT 'Thời gian gửi',
  PRIMARY KEY (`id`),
  KEY `idx_conversation` (`conversation_id`,`created_at`),
  KEY `idx_from_to` (`from_uid`,`to_uid`,`created_at`),
  KEY `idx_to_uid` (`to_uid`,`is_read`),
  KEY `idx_private_chat` (`from_uid`,`to_uid`),
  KEY `idx_group_chat` (`to_group`),
  KEY `idx_created` (`created_at`)
) ENGINE=InnoDB AUTO_INCREMENT=416 DEFAULT CHARSET=utf8mb4 COMMENT='Bảng tin nhắn IM';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `im_messages`
--

LOCK TABLES `im_messages` WRITE;
/*!40000 ALTER TABLE `im_messages` DISABLE KEYS */;
